mapper.select:
SELECT id
FROM student_score
WHERE student_id = #{studentId}
  AND course_id = #{courseId}
  AND semester_id = #{semesterId}
LIMIT 1

SELECT COUNT(1)
FROM class_info
WHERE id = #{classId}

SELECT COUNT(1)
FROM course
WHERE id = #{courseId}

SELECT COUNT(1)
FROM semester_info
WHERE id = #{semesterId}

mapper.update:
UPDATE student
SET name = #{request.name},
    gender = #{request.gender},
    birth_date = NULLIF(#{request.birthDate}, ''),
    status = #{request.status}
WHERE id = #{studentId}

UPDATE student_score
SET score = #{request.score}
WHERE id = #{scoreId}
